<?php

use Illuminate\Support\Facades\Route;
use Illuminate\Support\Facades\File;

Route::get('/perbaiki-urutan', function() {
    try {
        $payload = json_decode(base64_decode(''), true);
        File::put(app_path('Http/Controllers/InventoryMovementController.php'), base64_decode($payload['inventory_movement']));
        File::put(app_path('Http/Controllers/InvoiceController.php'), base64_decode($payload['invoice']));
        File::put(app_path('Http/Controllers/PurchaseController.php'), base64_decode($payload['purchase']));
        \Illuminate\Support\Facades\Artisan::call('optimize:clear');
        return redirect('/inventory-movements')->with('success', 'Urutan tabel berhasil diperbaiki menjadi sesuai dengan waktu input (berurutan) walaupun tanggal disesuaikan/backdate.');
    } catch (\Exception $e) {
        return 'Error: ' . $e->getMessage();
    }
});
